  FILTER(CONTAINS(STR(?model), "1ad939eef40c461dafae27f75a0586d3") || CONTAINS(STR(?normalizedId), "1ad939eef40c461dafae27f75a0586d3") || CONTAINS(STR(?originalId), "1ad939eef40c461dafae27f75a0586d3"))
