prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName ?taskCount ?eventCount ?gatewayCount ?participantCount ?flowCount WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography .
  ?choreo bbo:name ?choreoName .
  ?choreo tai:belongsTo ?defs .

  {
    SELECT ?choreo (COUNT(DISTINCT ?task) AS ?taskCount) WHERE {
      ?task a bboExt:ChoreographyTask .
      ?task tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
  {
    SELECT ?choreo (COUNT(DISTINCT ?event) AS ?eventCount) WHERE {
      ?event a bboExt:StartEvent .
      ?event tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
  {
    SELECT ?choreo (COUNT(DISTINCT ?gw) AS ?gatewayCount) WHERE {
      { ?gw a bboExt:ExclusiveGateway } UNION
      { ?gw a bboExt:ParallelGateway } UNION
      { ?gw a bboExt:EventBasedGateway } .
      ?gw tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
  {
    SELECT ?choreo (COUNT(DISTINCT ?part) AS ?participantCount) WHERE {
      ?part a bboExt:Participant .
      ?part tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
  {
    SELECT ?choreo (COUNT(DISTINCT ?flow) AS ?flowCount) WHERE {
      ?flow a bbo:SequenceFlow .
      ?flow tai:belongsTo ?choreo .
    } GROUP BY ?choreo
  }
}
LIMIT 25
